$(document).ready(function(){setTimeout(()=>{$('.faq-banner-section .doodle').addClass('animate')},2000);$(document).on('keyup','.search-block .search-input',function(){var searchString=$(this).val().trim();$.ajax({type:'POST',url:'/wp-admin/admin-ajax.php',dataType:'html',data:{action:'search_faq',courseName:$('#courseName').val(),searchString:searchString},success:function(res){if(res!=""){var response=res.substring(0,res.length-1);$('main .faq').html(response);$('main .faq .tabs').eq(0).addClass('faq-content');$(".faq-details .tab-buttons .tablinks ").removeClass('active');manageFaqstruct()}}})});function manageFaqstruct(){$(".faq .tab-content .tabcontent").removeClass('active');var tabs_array=["General","GENERAL","Admission","Academics","Program","PROGRAM","ADMISSION","ACADEMICS",];$.each(tabs_array,function(index,value){if($(".faq #"+value+"  .item").length>5){$("#"+value+"  .item").hide();$("#"+value+"  .item").slice(0,5).show();$("#"+value).append("<div class='show-all-link faq-"+value+"-show-more faq-show-more'><span>Load More</span></div>")}});$.each(tabs_array,function(index,value){if($(".faq #"+value).length){if($(".faq #"+value+"  .item").length>0){$(".faq .tab-content #"+value).addClass('active');$(".faq-details .tab-buttons ."+value).addClass('active');return!1}}})}
$(document).on('click','.faq-content .tabcontent .accordion-header',function(){var hideTab=!1;if($(this).hasClass('open')){var hideTab=!0}
$('.accordion-header').removeClass('open');$('.accordion-content').removeClass('open');if(hideTab==!1){$(this).addClass('open');$(this).next('.accordion-content').eq(0).addClass('open')}});$(document).on('click','.faq .tab-buttons .tablinks',function(){$('.faq .tab-buttons .tablinks').removeClass('active');$('.faq .tab-content .tabcontent').removeClass('active');$(this).addClass('active');var tabName=$(this).data('tab');$('#'+tabName).addClass('active')});$(document).on("click",".faq-content .tabcontent .faq-show-more",function(e){var tab_id=$(this).parents(".tabcontent").attr("id");var faq_count=$("#"+tab_id+" .item").length;$("#"+tab_id+" .item").slice(0,faq_count).show();$(".faq-"+tab_id+"-show-more").css("display","none");$("#"+tab_id).append("<div class='show-all-link faq-"+tab_id+"-show-less faq-show-less'><span>Load Less</span></div>")});$(document).on("click",".faq-content .tabcontent .faq-show-less",function(e){var tab_id=$(this).parents(".tabcontent").attr("id");$("#"+tab_id+" .item").hide();$("#"+tab_id+" .item").slice(0,5).show();$(".faq-"+tab_id+"-show-less").css("display","none");$("#"+tab_id).append("<div class='show-all-link faq-"+tab_id+"-show-more faq-show-more'><span>Load More</span></div>")})})